import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

// 1. Enable Mockito
@ExtendWith(MockitoExtension.class)
class OrderServiceTest {

    // 2. Create a Mock (fake) of the dependency
    @Mock
    private PaymentGateway paymentGateway;

    // 3. Inject the mock into the class we want to test
    @InjectMocks
    private OrderService orderService;

    @Test
    void testCheckout_Success() {
        // 4. Arrange: Train the mock to return true when charge(100) is called
        when(paymentGateway.charge(100)).thenReturn(true);

        // 5. Act: Call the real method we are testing
        boolean result = orderService.checkout(100);

        // 6. Assert: Verify the outcome
        assertTrue(result, "Checkout should succeed if payment passes");

        // Verify that the gateway was actually interacted with exactly once
        verify(paymentGateway, times(1)).charge(100);
    }

    @Test
    void testCheckout_Failure() {
        // Arrange: Train mock to throw an exception
        when(paymentGateway.charge(500)).thenThrow(new IllegalArgumentException("Limit exceeded"));

        // Act & Assert: Expect the exception to bubble up
        assertThrows(IllegalArgumentException.class, () -> {
            orderService.checkout(500);
        });
    }
}

